/** Jaskier Shared Pattern — Health hooks (TanStack Query) */

import { useQuery } from '@tanstack/react-query';
import { useApiClient } from '../api/context';

interface HealthLike {
  status?: string;
  uptime_seconds?: number;
  [key: string]: unknown;
}

interface SystemStatsLike {
  cpu_usage_percent?: number;
  memory_used_mb?: number;
  memory_total_mb?: number;
  [key: string]: unknown;
}

export function useSystemStatsQuery<T extends SystemStatsLike = SystemStatsLike>(enabled = true) {
  const { apiGetPolling } = useApiClient();
  return useQuery<T>({
    queryKey: ['system', 'stats'],
    queryFn: () => apiGetPolling<T>('/api/system/stats'),
    refetchInterval: 10_000,
    retry: false,
    enabled,
  });
}

export function useHealthQuery<T extends HealthLike = HealthLike>() {
  const { apiGetPolling } = useApiClient();
  return useQuery<T>({
    queryKey: ['health'],
    queryFn: () => apiGetPolling<T>('/api/health'),
    refetchInterval: 30_000,
    retry: false,
  });
}

export function useHealthStatus(): 'healthy' | 'offline' | 'degraded' {
  const { data, isError } = useHealthQuery();
  if (isError || !data) return 'offline';
  const s = data.status?.toLowerCase();
  if (s === 'ok' || s === 'healthy') return 'healthy';
  return 'degraded';
}
