/** Jaskier Shared Pattern — MCP Server hooks (TanStack Query) */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useApiClient } from '../api/context';

/**
 * MCP (Model Context Protocol) server configuration and metadata.
 *
 * Stores details about a registered MCP server including its transport mechanism,
 * connection URL/command, and enablement status.
 *
 * @example
 * ```typescript
 * const server: McpServer = {
 *   id: 'brave-search',
 *   name: 'Brave Search',
 *   transport: 'http',
 *   url: 'http://localhost:8000',
 *   enabled: true,
 *   timeout_secs: 30,
 *   created_at: '2025-04-11T12:00:00Z',
 *   updated_at: '2025-04-11T12:00:00Z',
 * };
 * ```
 */
export interface McpServer {
  /** Unique server identifier. */
  id: string;
  /** Human-readable server name. */
  name: string;
  /** Transport protocol: 'http' for HTTP endpoints, 'stdio' for local processes. */
  transport: 'http' | 'stdio';
  /** HTTP URL (required if transport is 'http'). */
  url?: string;
  /** Command to execute (required if transport is 'stdio'). */
  command?: string;
  /** Command-line arguments (for stdio transport). */
  args?: string;
  /** Whether the server is currently enabled and will be loaded. */
  enabled: boolean;
  /** Request timeout in seconds. */
  timeout_secs: number;
  /** ISO-8601 timestamp when the server was registered. */
  created_at: string;
  /** ISO-8601 timestamp of last update. */
  updated_at: string;
}

/**
 * Tool exposed by an MCP server after connection and discovery.
 *
 * Tools are discovered and cached after the server completes initialization.
 */
export interface McpDiscoveredTool {
  /** Unique tool identifier. */
  id: string;
  /** ID of the server providing this tool. */
  server_id: string;
  /** Tool name (as reported by the MCP server). */
  tool_name: string;
  /** Human-readable tool description. */
  description: string;
  /** ISO-8601 timestamp when the tool was discovered. */
  discovered_at: string;
}

/**
 * Query all registered MCP servers.
 *
 * Fetches the list of MCP servers configured in this environment. The cache
 * is considered fresh for 10 seconds before automatic refetch.
 *
 * @returns TanStack Query result containing array of {@link McpServer}
 *
 * @example
 * ```typescript
 * const { data: servers, isLoading } = useMcpServers();
 * return (
 *   <ul>
 *     {servers?.map(s => <li key={s.id}>{s.name}</li>)}
 *   </ul>
 * );
 * ```
 */
export function useMcpServers() {
  const { apiGet } = useApiClient();
  return useQuery<McpServer[]>({
    queryKey: ['mcp-servers'],
    queryFn: () => apiGet<McpServer[]>('/api/mcp/servers'),
    staleTime: 10_000,
  });
}

/**
 * Query tools provided by a specific MCP server.
 *
 * Only runs if `serverId` is provided. The cache is fresh for 30 seconds
 * before automatic refetch.
 *
 * @param serverId Server ID to query (pass null to disable)
 * @returns TanStack Query result containing array of {@link McpDiscoveredTool}
 *
 * @example
 * ```typescript
 * const [selected, setSelected] = useState<string | null>(null);
 * const { data: tools } = useMcpServerTools(selected);
 *
 * return (
 *   <ul>
 *     {tools?.map(t => <li key={t.id}>{t.tool_name}</li>)}
 *   </ul>
 * );
 * ```
 */
export function useMcpServerTools(serverId: string | null) {
  const { apiGet } = useApiClient();
  return useQuery<McpDiscoveredTool[]>({
    queryKey: ['mcp-server-tools', serverId],
    queryFn: () => apiGet<McpDiscoveredTool[]>(`/api/mcp/servers/${serverId}/tools`),
    enabled: !!serverId,
    staleTime: 30_000,
  });
}

/**
 * Mutation to register a new MCP server.
 *
 * Creates and registers an MCP server with either HTTP or stdio transport.
 * On success, automatically invalidates the MCP servers list to reflect the new server.
 *
 * @returns TanStack Query mutation
 *
 * @example
 * ```typescript
 * const mutation = useCreateMcpServer();
 * const handleCreate = async () => {
 *   await mutation.mutateAsync({
 *     name: 'Brave Search',
 *     transport: 'http',
 *     url: 'http://localhost:8000',
 *     timeout_secs: 30,
 *   });
 * };
 * ```
 */
export function useCreateMcpServer() {
  const { apiPost } = useApiClient();
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (body: { name: string; transport: string; url?: string; auth_token?: string; timeout_secs?: number }) =>
      apiPost('/api/mcp/servers', body),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['mcp-servers'] }),
  });
}

/**
 * Mutation to delete an MCP server.
 *
 * Removes the server and any cached tools from that server.
 * On success, automatically invalidates the servers list.
 *
 * @returns TanStack Query mutation that accepts server ID
 *
 * @example
 * ```typescript
 * const mutation = useDeleteMcpServer();
 * await mutation.mutateAsync('brave-search');
 * ```
 */
export function useDeleteMcpServer() {
  const { apiDelete } = useApiClient();
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => apiDelete(`/api/mcp/servers/${id}`),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['mcp-servers'] }),
  });
}

/**
 * Mutation to connect to an MCP server.
 *
 * Initiates connection to a registered but disconnected server. Upon successful
 * connection, the server will discover available tools. Automatically invalidates
 * the servers list.
 *
 * @returns TanStack Query mutation that accepts server ID
 *
 * @example
 * ```typescript
 * const mutation = useConnectMcpServer();
 * await mutation.mutateAsync('my-server-id');
 * ```
 */
export function useConnectMcpServer() {
  const { apiPost } = useApiClient();
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => apiPost(`/api/mcp/servers/${id}/connect`),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['mcp-servers'] }),
  });
}

/**
 * Mutation to disconnect from an MCP server.
 *
 * Closes the connection to a server. The server remains registered but will
 * be unavailable until the next connect call. Automatically invalidates the servers list.
 *
 * @returns TanStack Query mutation that accepts server ID
 *
 * @example
 * ```typescript
 * const mutation = useDisconnectMcpServer();
 * await mutation.mutateAsync('my-server-id');
 * ```
 */
export function useDisconnectMcpServer() {
  const { apiPost } = useApiClient();
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => apiPost(`/api/mcp/servers/${id}/disconnect`),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['mcp-servers'] }),
  });
}
