/** Jaskier Shared Pattern */
import { type RefObject, useEffect } from 'react';

/**
 * Detect clicks outside a referenced element and trigger a callback.
 *
 * Listens for mousedown events on the document and invokes the callback if the event
 * target is not within the element referenced by `ref`. Useful for closing dropdowns,
 * modals, popovers, and similar components that should dismiss when clicked outside.
 *
 * The listener is attached during mount and automatically cleaned up during unmount.
 * The callback is re-attached whenever `ref` or `onOutsideClick` change to ensure
 * the latest closure is used.
 *
 * @param ref React ref pointing to the element to detect clicks outside of
 * @param onOutsideClick Callback invoked when a mousedown occurs outside the element
 *
 * @example
 * ```typescript
 * const dropdownRef = useRef<HTMLDivElement>(null);
 * const [isOpen, setIsOpen] = useState(false);
 *
 * useOutsideClick(dropdownRef, () => setIsOpen(false));
 *
 * return (
 *   <div ref={dropdownRef}>
 *     {isOpen && <Dropdown />}
 *   </div>
 * );
 * ```
 */
export function useOutsideClick(ref: RefObject<HTMLElement | null>, onOutsideClick: () => void): void {
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        onOutsideClick();
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [ref, onOutsideClick]);
}
