/**
 * Safe toast wrapper (M1-12) — sonner is an optional peerDependency.
 * If not installed, toast calls are silently ignored instead of crashing.
 *
 * Usage:
 *   import { safeToast } from '@jaskier/core/utils';
 *   safeToast.error('Something failed');
 *   safeToast.success('Operation completed');
 *   safeToast.info('FYI');
 *   safeToast.warning('Heads up');
 *
 * Solves M4-21: hardcoded toast import crashes apps without sonner.
 * Queues calls made before sonner finishes loading.
 */

type ToastFn = (msg: string, opts?: Record<string, unknown>) => void;

// biome-ignore lint: lazy-loaded optional dependency
let _toast: Record<string, ToastFn> | null = null;
let _loaded = false;
const _queue: Array<{ method: string; msg: string; opts?: Record<string, unknown> }> = [];

function ensureLoaded(): void {
  if (_loaded) return;
  _loaded = true;
  import('sonner')
    .then((m) => {
      _toast = m.toast as unknown as Record<string, ToastFn>;
      for (const item of _queue) {
        _toast[item.method]?.(item.msg, item.opts);
      }
      _queue.length = 0;
    })
    .catch(() => {
      _queue.length = 0;
    });
}

function invoke(method: string, msg: string, opts?: Record<string, unknown>): void {
  ensureLoaded();
  if (_toast) {
    _toast[method]?.(msg, opts);
  } else {
    _queue.push({ method, msg, opts });
  }
}

export const safeToast = {
  error(msg: string, opts?: Record<string, unknown>) {
    invoke('error', msg, opts);
  },
  success(msg: string, opts?: Record<string, unknown>) {
    invoke('success', msg, opts);
  },
  info(msg: string, opts?: Record<string, unknown>) {
    invoke('info', msg, opts);
  },
  warning(msg: string, opts?: Record<string, unknown>) {
    invoke('warning', msg, opts);
  },
};
