/** Jaskier Shared Pattern — Browser Proxy Status hooks (TanStack Query) */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useApiClient } from '../api/context';

/**
 * Real-time status and health information from the browser proxy service.
 *
 * Used to display connection health, worker availability, queue status, and error information
 * in the UI. The health object is populated when the proxy is configured and reachable.
 *
 * @example
 * ```typescript
 * const status = useBrowserProxyStatus({ reachable: true, health: { workers_ready: 4 } });
 * if (status.health) {
 *   console.log(`${status.health.workers_ready}/${status.health.pool_size} workers available`);
 * }
 * ```
 */
export interface BrowserProxyStatus {
  /** Whether the proxy service is configured in this environment. */
  configured: boolean;
  /** Whether the proxy service is currently reachable and responding. */
  reachable: boolean;
  /** The public URL of the browser proxy service (if configured). */
  proxy_url?: string;
  /** Error message if the proxy failed to initialize or connect. */
  error?: string;
  /** Detailed health metrics from the proxy service (present only when configured and reachable). */
  health?: {
    /** Whether the proxy is ready to accept requests. */
    ready: boolean;
    /** Whether the proxy is authenticated with the remote browser service. */
    logged_in: boolean;
    /** Number of browser workers currently idle and ready for new tasks. */
    workers_ready: number;
    /** Number of browser workers currently executing tasks. */
    workers_busy: number;
    /** Total capacity of the worker pool. */
    pool_size: number;
    /** Number of requests waiting to be assigned to a worker. */
    queue_length: number;
    /** Total HTTP requests processed since startup. */
    total_requests: number;
    /** Total request failures since startup. */
    total_errors: number;
    /** Proxy service uptime in seconds. */
    uptime_seconds: number;
  };
  /** Login-specific status information (present when proxy supports authentication). */
  login?: {
    /** Whether the proxy is authenticated (ready to spawn workers). */
    logged_in: boolean;
    /** Whether a login operation is currently in progress. */
    login_in_progress: boolean;
    /** Number of workers that are ready to use. */
    workers_ready: number;
    /** Size of the worker pool. */
    pool_size: number;
    /** Error message from the last login attempt (if any). */
    last_login_error: string | null;
    /** Age of the authentication file in seconds (or null if never set). */
    auth_file_age_seconds: number | null;
  };
}

/**
 * Query the browser proxy status and health metrics.
 *
 * Returns a TanStack Query result with automatic cache management and optional polling.
 * The proxy status includes configuration state, reachability, worker pool metrics, and error details.
 *
 * @param polling If true, automatically refetch status every 3 seconds. Defaults to false.
 * @returns TanStack Query result containing {@link BrowserProxyStatus}
 *
 * @example
 * ```typescript
 * // One-time check
 * const { data: status } = useBrowserProxyStatus();
 *
 * // Continuous polling for real-time updates
 * const { data: status, isFetching } = useBrowserProxyStatus(true);
 * if (isFetching) console.log('Updating status...');
 * ```
 */
export function useBrowserProxyStatus(polling = false) {
  const { apiGet } = useApiClient();
  return useQuery<BrowserProxyStatus>({
    queryKey: ['browser-proxy-status'],
    queryFn: () => apiGet<BrowserProxyStatus>('/api/browser-proxy/status'),
    refetchInterval: polling ? 3000 : false,
    refetchOnWindowFocus: false,
  });
}

/**
 * Mutation to log in to the browser proxy service.
 *
 * Initiates an authentication flow with the remote browser service. On success,
 * the proxy will be marked as logged in and workers will become available.
 * Automatically invalidates the status cache after completion.
 *
 * @returns TanStack Query mutation that returns status confirmation
 *
 * @example
 * ```typescript
 * const mutation = useBrowserProxyLogin();
 * const handleLogin = async () => {
 *   try {
 *     const result = await mutation.mutateAsync();
 *     console.log(result.message); // "Logged in successfully"
 *   } catch (e) {
 *     console.error('Login failed:', e.message);
 *   }
 * };
 * ```
 */
export function useBrowserProxyLogin() {
  const { apiPost } = useApiClient();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: () => apiPost<{ status: string; message?: string }>('/api/browser-proxy/login'),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['browser-proxy-status'] });
    },
  });
}

/**
 * Mutation to reinitialize the browser proxy service.
 *
 * Restarts the worker pool and recovers from transient errors. Useful when the proxy
 * is in a degraded state but still configured. Automatically invalidates the status cache.
 *
 * @returns TanStack Query mutation that returns status and updated worker count
 *
 * @example
 * ```typescript
 * const mutation = useBrowserProxyReinit();
 * const handleReinit = async () => {
 *   const result = await mutation.mutateAsync();
 *   console.log(`Workers ready: ${result.workers_ready}`);
 * };
 * ```
 */
export function useBrowserProxyReinit() {
  const { apiPost } = useApiClient();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: () => apiPost<{ status: string; workers_ready?: number }>('/api/browser-proxy/reinit'),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['browser-proxy-status'] });
    },
  });
}

/**
 * Mutation to log out from the browser proxy service.
 *
 * Terminates the authentication session with the remote browser service.
 * Workers will no longer be available until the next login. Automatically
 * invalidates the status cache after completion.
 *
 * @returns TanStack Query mutation that returns status confirmation
 *
 * @example
 * ```typescript
 * const mutation = useBrowserProxyLogout();
 * const handleLogout = async () => {
 *   await mutation.mutateAsync();
 *   console.log('Logged out');
 * };
 * ```
 */
export function useBrowserProxyLogout() {
  const { apiDelete } = useApiClient();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: () => apiDelete<{ status: string }>('/api/browser-proxy/logout'),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['browser-proxy-status'] });
    },
  });
}
