/** Jaskier Shared Pattern */
// packages/core/src/api/client.ts
/**
 * @jaskier/core — Typed API Client Factory
 * ==========================================
 * Full-featured fetch wrapper with:
 * - Exponential backoff + jitter retry
 * - Per-attempt timeout via AbortController
 * - In-flight GET request deduplication
 * - Toast notifications for auth errors (401/403) and timeouts
 * - FormData upload support
 *
 * Usage:
 *   import { createApiClient } from '@jaskier/core/api';
 *   export const { apiGet, apiPost, ... } = createApiClient({
 *     flyUrl: 'https://my-app.fly.dev',
 *     localPort: 8081,
 *     authSecret: env.VITE_AUTH_SECRET,
 *   });
 */

import { safeToast as toast } from '../utils/safeToast';

// -------------------------------------------------------------------
// Config
// -------------------------------------------------------------------

export interface ApiClientConfig {
  /** Fly.io production backend URL */
  flyUrl: string;
  /** Local dev port (used when not in prod or on localhost) */
  localPort: number;
  /** Auth secret (from VITE_AUTH_SECRET env var) */
  authSecret?: string | undefined;
  /** Max retries for idempotent requests (default: 3) */
  maxRetries?: number;
  /** Base delay in ms for exponential backoff (default: 1000) */
  retryBaseMs?: number;
  /** Per-attempt timeout in ms (default: 45000) */
  requestTimeoutMs?: number;
}

// -------------------------------------------------------------------
// Error class
// -------------------------------------------------------------------

export class ApiError extends Error {
  readonly status: number;
  readonly statusText: string;
  readonly body: unknown;

  constructor(status: number, statusText: string, body: unknown) {
    super(`API Error ${status}: ${statusText}`);
    this.name = 'ApiError';
    this.status = status;
    this.statusText = statusText;
    this.body = body;
  }
}

// -------------------------------------------------------------------
// Shared types
// -------------------------------------------------------------------

export interface HealthStatus {
  ready: boolean;
  uptime_seconds?: number;
}

// -------------------------------------------------------------------
// Retryable statuses
// -------------------------------------------------------------------

const RETRYABLE_STATUSES = new Set([408, 429, 500, 502, 503, 504]);

// -------------------------------------------------------------------
// Factory
// -------------------------------------------------------------------

export function createApiClient(config: ApiClientConfig) {
  const { flyUrl, localPort, authSecret, maxRetries = 3, retryBaseMs = 1000, requestTimeoutMs = 45_000 } = config;

  const isLocalhost =
    typeof window !== 'undefined' &&
    (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1');

  // VITE_BACKEND_URL env var overrides everything; fall back to fly URL in prod,
  // or empty string (relative proxy) in local dev.
  // Note: import.meta.env is resolved by Vite at build time.
  // Vite resolves import.meta.env at build time; cast needed for non-Vite consumers
  const meta = import.meta as unknown as { env?: Record<string, string | boolean | undefined> };
  const BASE_URL: string =
    (meta.env?.['VITE_BACKEND_URL'] as string | undefined) ??
    (meta.env?.['PROD'] && !isLocalhost ? flyUrl : `http://localhost:${String(localPort)}`);

  // -------------------------------------------------------------------
  // Retry wrapper
  // -------------------------------------------------------------------

  /**
   * Retry with exponential backoff + jitter.
   * - Network errors (TypeError): always retried regardless of method.
   * - Retryable HTTP statuses (408, 429, 500, 502, 503, 504): retried only
   *   for idempotent methods (GET, HEAD) to avoid duplicating side-effects.
   */
  async function fetchWithRetry(url: string, init: RequestInit, retries = maxRetries): Promise<Response> {
    const method = init.method?.toUpperCase() ?? 'GET';
    const isIdempotent = method === 'GET' || method === 'HEAD';
    let lastError: Error | undefined;

    for (let attempt = 0; attempt <= retries; attempt++) {
      // Per-attempt timeout via AbortController
      const timeoutController = new AbortController();
      const timeoutId = setTimeout(() => timeoutController.abort(), requestTimeoutMs);

      // Combine with caller-provided signal (if any) so both can abort
      const signal = init.signal ? AbortSignal.any([init.signal, timeoutController.signal]) : timeoutController.signal;

      try {
        const response = await fetch(url, { ...init, signal });
        clearTimeout(timeoutId);

        // Success or non-retryable client error — return immediately
        if (response.ok || !RETRYABLE_STATUSES.has(response.status)) {
          return response;
        }

        // Retryable HTTP status — only retry idempotent methods
        if (isIdempotent && attempt < retries) {
          const delay = retryBaseMs * 2 ** attempt + Math.random() * 500;
          console.warn(
            `[api] HTTP ${String(response.status)} on ${method} ${url}, retrying in ${String(Math.round(delay))}ms (${String(attempt + 1)}/${String(retries)})`,
          );
          await new Promise((r) => setTimeout(r, delay));
          continue;
        }

        return response; // Last attempt or non-idempotent — return as-is
      } catch (err) {
        clearTimeout(timeoutId);

        // Timeout abort — show toast and throw immediately (no retry)
        if (timeoutController.signal.aborted) {
          toast.error('Request timed out. Please try again.');
          throw new Error('Request timed out');
        }

        // Caller-provided signal aborted — propagate without retry
        if (init.signal?.aborted) {
          throw err;
        }

        lastError = err instanceof Error ? err : new Error(String(err));
        // Network failure (TypeError) — retry regardless of method
        if (attempt < retries && err instanceof TypeError) {
          const delay = retryBaseMs * 2 ** attempt + Math.random() * 500;
          console.warn(
            `[api] Network error on ${method} ${url}, retrying in ${String(Math.round(delay))}ms (${String(attempt + 1)}/${String(retries)})`,
          );
          await new Promise((r) => setTimeout(r, delay));
          continue;
        }
        throw err;
      }
    }

    throw lastError ?? new Error('Request failed after retries');
  }

  // -------------------------------------------------------------------
  // In-flight request deduplication
  // -------------------------------------------------------------------
  // If an identical GET request is already pending, return the same promise
  // instead of making a duplicate request. Keyed by full URL.

  const inflightRequests = new Map<string, Promise<unknown>>();

  // -------------------------------------------------------------------
  // Internal fetch helper
  // -------------------------------------------------------------------

  async function apiFetchInternal<T>(url: string, options: RequestInit, retries?: number): Promise<T> {
    const response = await fetchWithRetry(
      url,
      {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...(authSecret ? { Authorization: `Bearer ${authSecret}` } : {}),
          ...options.headers,
        },
      },
      retries,
    );

    if (!response.ok) {
      let body: unknown;
      try {
        body = await response.json();
      } catch {
        body = await response.text().catch(() => null);
      }

      if (response.status === 401) {
        toast.error('Authentication required', {
          description: 'Check your AUTH_SECRET configuration',
        });
      } else if (response.status === 403) {
        toast.error('Access denied', {
          description: 'Insufficient permissions for this action',
        });
      }

      throw new ApiError(response.status, response.statusText, body);
    }

    // Handle 204 No Content
    if (response.status === 204) {
      return undefined as T;
    }

    return response.json() as Promise<T>;
  }

  async function apiFetch<T>(path: string, options: RequestInit = {}, retries?: number): Promise<T> {
    const url = `${BASE_URL}${path}`;
    const method = options.method?.toUpperCase() ?? 'GET';

    // Deduplicate concurrent identical GET requests
    if (method === 'GET') {
      const existing = inflightRequests.get(url);
      if (existing) {
        return existing as Promise<T>;
      }

      const promise = apiFetchInternal<T>(url, options, retries).finally(() => {
        inflightRequests.delete(url);
      });
      inflightRequests.set(url, promise);
      return promise;
    }

    return apiFetchInternal<T>(url, options, retries);
  }

  // -------------------------------------------------------------------
  // Public API
  // -------------------------------------------------------------------

  async function apiGet<T>(path: string): Promise<T> {
    return apiFetch<T>(path, { method: 'GET' });
  }

  /** Polling-safe GET — no fetch-level retries, no console warnings on failure. */
  async function apiGetPolling<T>(path: string): Promise<T> {
    return apiFetch<T>(path, { method: 'GET' }, 0);
  }

  async function apiPostFormData<T>(path: string, body: FormData): Promise<T> {
    const url = `${BASE_URL}${path}`;
    const response = await fetchWithRetry(url, {
      method: 'POST',
      body,
      headers: {
        ...(authSecret ? { Authorization: `Bearer ${authSecret}` } : {}),
      },
    });

    if (!response.ok) {
      let errBody: unknown;
      try {
        errBody = await response.json();
      } catch {
        errBody = await response.text().catch(() => null);
      }
      throw new ApiError(response.status, response.statusText, errBody);
    }

    if (response.status === 204) {
      return undefined as T;
    }

    return response.json() as Promise<T>;
  }

  async function apiPost<T>(path: string, body?: unknown): Promise<T> {
    return apiFetch<T>(path, {
      method: 'POST',
      ...(body !== undefined && { body: JSON.stringify(body) }),
    });
  }

  async function apiPatch<T>(path: string, body?: unknown): Promise<T> {
    return apiFetch<T>(path, {
      method: 'PATCH',
      ...(body !== undefined && { body: JSON.stringify(body) }),
    });
  }

  async function apiDelete<T>(path: string): Promise<T> {
    return apiFetch<T>(path, { method: 'DELETE' });
  }

  // -------------------------------------------------------------------
  // Health check
  // -------------------------------------------------------------------

  /** Lightweight readiness check — no retries, short timeout. */
  async function checkHealth(): Promise<HealthStatus> {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 5000);

      const response = await fetch(`${BASE_URL}/api/health/ready`, {
        method: 'GET',
        signal: controller.signal,
      });

      clearTimeout(timeout);

      if (response.ok) {
        return (await response.json()) as HealthStatus;
      }

      // 503 = starting up
      if (response.status === 503) {
        const body = (await response.json()) as HealthStatus;
        return { ready: false, ...(body.uptime_seconds !== undefined && { uptime_seconds: body.uptime_seconds }) };
      }

      return { ready: false };
    } catch {
      return { ready: false };
    }
  }

  return {
    BASE_URL,
    apiGet,
    apiGetPolling,
    apiPost,
    apiPatch,
    apiDelete,
    apiPostFormData,
    checkHealth,
  };
}
