/**
 * @jaskier/core — API Client Context
 * ====================================
 * Provides API client functions to shared hooks via React Context.
 *
 * Apps wrap their tree with <ApiClientProvider> passing the app-specific
 * API client instance (created via createApiClient). Shared hooks use
 * useApiClient() to access apiGet, apiPost, etc.
 */

import { createContext, type ReactNode, useContext } from 'react';

// ============================================================================
// TYPES
// ============================================================================

export interface ApiClientFunctions {
  apiGet: <T>(path: string) => Promise<T>;
  apiGetPolling: <T>(path: string) => Promise<T>;
  apiPost: <T>(path: string, body?: unknown) => Promise<T>;
  apiPatch: <T>(path: string, body?: unknown) => Promise<T>;
  apiDelete: <T>(path: string) => Promise<T>;
  apiPostFormData: <T>(path: string, body: FormData) => Promise<T>;
  BASE_URL: string;
}

// ============================================================================
// CONTEXT
// ============================================================================

const ApiClientContext = createContext<ApiClientFunctions | null>(null);

// ============================================================================
// PROVIDER
// ============================================================================

interface ApiClientProviderProps {
  client: ApiClientFunctions;
  children: ReactNode;
}

export function ApiClientProvider({ client, children }: ApiClientProviderProps) {
  return <ApiClientContext.Provider value={client}>{children}</ApiClientContext.Provider>;
}

// ============================================================================
// HOOK
// ============================================================================

/**
 * Returns the API client functions from the nearest ApiClientProvider.
 * Throws if used outside of a provider.
 */
export function useApiClient(): ApiClientFunctions {
  const ctx = useContext(ApiClientContext);
  if (!ctx) {
    throw new Error('useApiClient must be used within an <ApiClientProvider>. Wrap your app with it.');
  }
  return ctx;
}
