/** Jaskier Shared Pattern — Auth status hook (API Key + OAuth) with configurable paths */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useCallback, useEffect, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useApiClient } from '../api/context';
import { safeToast as toast } from '../utils/safeToast';

export type AuthPhase = 'idle' | 'oauth_pending' | 'saving_key' | 'authenticated' | 'error';

/** Minimal shape — apps can pass their own AuthStatus type */
interface AuthStatusLike {
  authenticated?: boolean;
  expired?: boolean;
  method?: 'oauth' | 'api_key' | 'env' | null;
  user_email?: string;
  expires_at?: number;
  oauth_available?: boolean;
  [key: string]: unknown;
}

interface AuthLoginResponseLike {
  auth_url: string;
  [key: string]: unknown;
}

interface SaveApiKeyResponseLike {
  [key: string]: unknown;
}

export interface UseAuthStatusReturn {
  status: AuthStatusLike | undefined;
  isLoading: boolean;
  phase: AuthPhase;
  authMethod: 'oauth' | 'api_key' | 'env' | null;
  isDismissed: boolean;
  dismiss: () => void;
  login: () => void;
  saveApiKey: (key: string) => void;
  deleteApiKey: () => void;
  logout: () => void;
  cancel: () => void;
  authUrl: string | null;
  errorMessage: string | null;
  isMutating: boolean;
}

/** API functions that can be injected directly (for apps without ApiClientProvider) */
export interface AuthApiClient {
  apiGet: <T>(path: string) => Promise<T>;
  apiPost: <T>(path: string, body?: unknown) => Promise<T>;
  apiDelete: <T>(path: string) => Promise<T>;
}

/** Configuration for customizing API paths and behavior */
export interface UseAuthStatusConfig {
  /** API endpoint paths (defaults to /api/auth/*) */
  paths?: {
    status?: string;
    login?: string;
    logout?: string;
    apikey?: string;
  };
  /** i18n key prefix (defaults to 'auth') */
  i18nPrefix?: string;
  /** Query key for TanStack Query cache (defaults to ['auth-status']) */
  queryKey?: readonly string[];
  /** localStorage key for dismiss state (defaults to 'jaskier_auth_dismissed') */
  dismissedKey?: string;
  /**
   * Direct API client injection — use this when ApiClientProvider is not available.
   * If provided, useApiClient() context is NOT used.
   */
  apiClient?: AuthApiClient;
}

const DEFAULT_PATHS = {
  status: '/api/auth/status',
  login: '/api/auth/login',
  logout: '/api/auth/logout',
  apikey: '/api/auth/apikey',
} as const;

const DEFAULT_QUERY_KEY = ['auth-status'] as const;
const DEFAULT_DISMISSED_KEY = 'jaskier_auth_dismissed';
const DEFAULT_I18N_PREFIX = 'auth';

function readDismissed(key: string): boolean {
  try {
    return localStorage.getItem(key) === 'true';
  } catch {
    return false;
  }
}

/**
 * Shared auth status hook supporting both ApiClientProvider context
 * and direct API client injection.
 *
 * @example Default (uses ApiClientProvider context):
 *   useAuthStatus()
 *
 * @example Custom paths (e.g. ClaudeHydra Google OAuth):
 *   useAuthStatus({
 *     paths: { status: '/api/auth/google/status', login: '/api/auth/google/login', ... },
 *     i18nPrefix: 'googleAuth',
 *     queryKey: ['google-auth-status'],
 *     apiClient: { apiGet, apiPost, apiDelete },
 *   })
 */
export function useAuthStatus(config?: UseAuthStatusConfig): UseAuthStatusReturn {
  const { t } = useTranslation();

  const paths = { ...DEFAULT_PATHS, ...config?.paths };
  const i18n = config?.i18nPrefix ?? DEFAULT_I18N_PREFIX;
  const queryKey = config?.queryKey ?? DEFAULT_QUERY_KEY;
  const dismissedKey = config?.dismissedKey ?? DEFAULT_DISMISSED_KEY;

  // Resolve API client: injected directly or from context
  let api: AuthApiClient;
  if (config?.apiClient) {
    api = config.apiClient;
  } else {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    const ctx = useApiClient();
    api = ctx;
  }

  const qc = useQueryClient();

  const [localPhase, setLocalPhase] = useState<AuthPhase>('idle');
  const [isDismissed, setIsDismissed] = useState(() => readDismissed(dismissedKey));
  const [authUrl, setAuthUrl] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Stop polling helper
  const stopPolling = useCallback(() => {
    if (pollRef.current) {
      clearInterval(pollRef.current);
      pollRef.current = null;
    }
  }, []);

  // Cleanup on unmount
  useEffect(() => stopPolling, [stopPolling]);

  const { data: status, isLoading } = useQuery<AuthStatusLike>({
    queryKey,
    queryFn: async () => {
      try {
        return await api.apiGet<AuthStatusLike>(paths.status);
      } catch {
        // 401/403/404 = not authenticated — don't throw, return unauthenticated status
        return { authenticated: false, expired: true } as AuthStatusLike;
      }
    },
    staleTime: 300_000,
    refetchInterval: false,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    retry: false,
  });

  // Derive phase from backend status + local state
  const phase: AuthPhase = status?.authenticated && !status.expired ? 'authenticated' : localPhase;
  const authMethod = status?.method ?? null;

  // Stop polling when authenticated
  useEffect(() => {
    if (status?.authenticated && localPhase === 'oauth_pending') {
      stopPolling();
      setLocalPhase('idle');
      setAuthUrl(null);
      toast.success(t(`${i18n}.loginSuccess`));
    }
  }, [status?.authenticated, localPhase, stopPolling, t, i18n]);

  // ── OAuth flow ──────────────────────────────────────────────
  const loginMutation = useMutation({
    mutationFn: () => api.apiPost<AuthLoginResponseLike>(paths.login),
    onSuccess: (data) => {
      setAuthUrl(data.auth_url);
      setErrorMessage(null);
      setLocalPhase('oauth_pending');

      const win = window.open(data.auth_url, '_blank', 'noopener');
      if (!win) {
        toast.info(t(`${i18n}.popupBlocked`));
        return;
      }

      // Start polling every 2s, auto-stop after 5 minutes
      stopPolling();
      pollRef.current = setInterval(() => {
        qc.invalidateQueries({ queryKey });
      }, 2000);
      setTimeout(
        () => {
          if (pollRef.current) {
            stopPolling();
            setLocalPhase('idle');
            toast.info(t(`${i18n}.loginTimeout`, 'Login timed out — please try again'));
          }
        },
        5 * 60 * 1000,
      );
    },
    onError: (err) => {
      const msg = err instanceof Error ? err.message : t(`${i18n}.loginError`);
      setErrorMessage(msg);
      toast.error(t(`${i18n}.loginError`));
      setLocalPhase('error');
    },
  });

  // ── API Key flow ───────────────────────────────────────────────────
  const saveKeyMutation = useMutation({
    mutationFn: (key: string) => api.apiPost<SaveApiKeyResponseLike>(paths.apikey, { api_key: key }),
    onMutate: () => {
      setLocalPhase('saving_key');
      setErrorMessage(null);
    },
    onSuccess: () => {
      setLocalPhase('idle');
      qc.invalidateQueries({ queryKey });
      toast.success(t(`${i18n}.apiKeySaved`));
    },
    onError: (err) => {
      const msg = err instanceof Error ? err.message : t(`${i18n}.invalidApiKey`);
      setErrorMessage(msg);
      toast.error(t(`${i18n}.invalidApiKey`));
      setLocalPhase('error');
    },
  });

  const deleteKeyMutation = useMutation({
    mutationFn: () => api.apiDelete(paths.apikey),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey });
      toast.success(t(`${i18n}.apiKeyDeleted`));
    },
  });

  // ── Logout ─────────────────────────────────────────────────────────
  const logoutMutation = useMutation({
    mutationFn: () => api.apiPost(paths.logout),
    onSuccess: () => {
      setLocalPhase('idle');
      setAuthUrl(null);
      setErrorMessage(null);
      qc.invalidateQueries({ queryKey });
      toast.success(t(`${i18n}.logoutSuccess`));
    },
  });

  const login = useCallback(() => {
    setErrorMessage(null);
    loginMutation.mutate();
  }, [loginMutation]);

  const saveApiKey = useCallback(
    (key: string) => {
      saveKeyMutation.mutate(key);
    },
    [saveKeyMutation],
  );

  const deleteApiKey = useCallback(() => {
    deleteKeyMutation.mutate();
  }, [deleteKeyMutation]);

  const logout = useCallback(() => {
    logoutMutation.mutate();
  }, [logoutMutation]);

  const cancel = useCallback(() => {
    stopPolling();
    setLocalPhase('idle');
    setAuthUrl(null);
    setErrorMessage(null);
  }, [stopPolling]);

  const dismiss = useCallback(() => {
    try {
      localStorage.setItem(dismissedKey, 'true');
    } catch {
      /* ignore */
    }
    setIsDismissed(true);
  }, [dismissedKey]);

  return {
    status,
    isLoading,
    phase,
    authMethod,
    isDismissed,
    dismiss,
    login,
    saveApiKey,
    deleteApiKey,
    logout,
    cancel,
    authUrl,
    errorMessage,
    isMutating:
      loginMutation.isPending || saveKeyMutation.isPending || deleteKeyMutation.isPending || logoutMutation.isPending,
  };
}
