/** Jaskier Shared Pattern — Settings hooks (TanStack Query) with optional telemetry sync */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useApiClient } from '../api/context';

/** Re-usable type — apps re-export Settings from @jaskier/core/schemas */
interface SettingsLike {
  [key: string]: unknown;
}

/** API functions that can be injected directly (for apps without ApiClientProvider) */
interface SettingsApiClient {
  apiGet: <T>(path: string) => Promise<T>;
  apiPost: <T>(path: string, body?: unknown) => Promise<T>;
}

/** Configuration for customizing settings behavior */
export interface UseSettingsConfig {
  /**
   * localStorage key for telemetry setting.
   * When provided, the hook will sync the `telemetry` field to localStorage
   * on each successful fetch, enabling non-hook consumers (e.g. ErrorBoundary
   * class components) to read the telemetry flag.
   */
  telemetryLocalStorageKey?: string;
  /**
   * Direct API client injection — use this when ApiClientProvider is not available.
   * If provided, useApiClient() context is NOT used.
   */
  apiClient?: SettingsApiClient;
}

export function useSettingsQuery<T extends SettingsLike = SettingsLike>(config?: UseSettingsConfig) {
  let api: SettingsApiClient;
  if (config?.apiClient) {
    api = config.apiClient;
  } else {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    api = useApiClient();
  }

  const telemetryKey = config?.telemetryLocalStorageKey;

  return useQuery<T>({
    queryKey: ['settings'],
    queryFn: async () => {
      const settings = await api.apiGet<T>('/api/settings');
      // Sync telemetry flag to localStorage for non-hook consumers (ErrorBoundary)
      if (telemetryKey) {
        try {
          localStorage.setItem(telemetryKey, String((settings as SettingsLike)['telemetry'] ?? false));
        } catch {
          /* ignore */
        }
      }
      return settings;
    },
  });
}

export function useUpdateSettingsMutation<T extends SettingsLike = SettingsLike>(config?: UseSettingsConfig) {
  let api: SettingsApiClient;
  if (config?.apiClient) {
    api = config.apiClient;
  } else {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    api = useApiClient();
  }

  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (settings: Partial<T>) => api.apiPost<T>('/api/settings', settings),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['settings'] });
    },
  });
}

/**
 * Creates a telemetry checker function for use in class components or non-hook contexts.
 * Reads from localStorage — must be paired with `useSettingsQuery({ telemetryLocalStorageKey })`.
 *
 * @example
 *   export const isTelemetryEnabled = createTelemetryChecker('claude-hydra-telemetry');
 */
export function createTelemetryChecker(localStorageKey: string): () => boolean {
  return () => {
    try {
      return localStorage.getItem(localStorageKey) === 'true';
    } catch {
      return false;
    }
  };
}
