/** Jaskier Shared Pattern */
// packages/core/src/i18n/createI18nConfig.ts
/**
 * @jaskier/core — i18n Config Factory
 * =====================================
 * Generates the standard per-app i18next overrides and initializes i18n.
 * Differs per app only in: appName (title/logoAlt) and providerName (auth subtitle).
 *
 * Usage:
 *   import { createI18nConfig } from '@jaskier/core/i18n';
 *   createI18nConfig('GeminiHydra', 'Google');
 */

import { initI18n } from '@jaskier/i18n';

export interface I18nAppConfig {
  /** App display name used in titles and logo alt text */
  appName: string;
  /**
   * Provider name used in auth subtitle, e.g. 'Google', 'OpenAI', 'Grok', 'DeepSeek'
   */
  providerName: string;
}

/**
 * Initialize i18next with standard Hydra overrides for the given app.
 * Call once at app startup (in src/i18n/index.ts).
 */
export function createI18nConfig(appName: string, providerName: string): void {
  void initI18n({
    overrides: {
      en: {
        home: {
          subtitle: 'AI Swarm Control Center — start a new chat or continue a previous conversation.',
          newChat: 'New Chat',
          recentChats: 'Recent Chats',
          noChats: 'No chats yet. Start a new conversation!',
          msg: 'msg',
          logoAlt: `${appName} Logo`,
          title: appName,
          badges: {
            agents: '12 Agents',
            pipeline: '5-Phase Pipeline',
            multiProvider: 'Multi-Provider',
            swarmArch: 'Swarm Architecture',
          },
        },
        auth: {
          loginTitle: `Sign in to ${appName}`,
          loginSubtitle: `Connect your ${providerName} API credentials to start using the AI Swarm.`,
        },
      },
      pl: {
        home: {
          subtitle: 'Centrum Sterowania Rojem AI — rozpocznij nowy czat lub kontynuuj rozmowę.',
          newChat: 'Nowy Czat',
          recentChats: 'Ostatnie Czaty',
          noChats: 'Brak czatów. Rozpocznij nową rozmowę!',
          msg: 'wiad.',
          logoAlt: `Logo ${appName}`,
          title: appName,
          badges: {
            agents: '12 Agentów',
            pipeline: '5-fazowy Pipeline',
            multiProvider: 'Wielu Dostawców',
            swarmArch: 'Architektura Roju',
          },
        },
        auth: {
          loginTitle: `Zaloguj się do ${appName}`,
          loginSubtitle: `Podłącz swoje dane uwierzytelniające ${providerName} API, aby zacząć korzystać z Roju AI.`,
        },
      },
    },
  });
}
