/// <reference types="node" />
// @jaskier/core — Bun.Terminal API utility module
//
// B601-T9: Explore Bun.Terminal API for terminal rendering.
// Bun.Terminal provides a low-level API for terminal manipulation:
// - Raw mode input handling
// - ANSI escape sequence generation
// - Terminal size detection
// - Cursor positioning and styling
//
// This module provides higher-level abstractions for use in JaskierTUI
// and CLI tools within the workspace.
//
// NOTE: This module is Bun-only and should NOT be imported in browser builds.
// Use via '@jaskier/core/utils' subpath import.

/** Terminal dimensions */
export interface TerminalSize {
  columns: number;
  rows: number;
}

/** ANSI color codes for terminal output */
export const ANSI = {
  // Reset
  reset: '\x1b[0m',
  // Styles
  bold: '\x1b[1m',
  dim: '\x1b[2m',
  italic: '\x1b[3m',
  underline: '\x1b[4m',
  // Foreground colors
  black: '\x1b[30m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
  white: '\x1b[37m',
  // Bright foreground
  brightRed: '\x1b[91m',
  brightGreen: '\x1b[92m',
  brightYellow: '\x1b[93m',
  brightBlue: '\x1b[94m',
  brightMagenta: '\x1b[95m',
  brightCyan: '\x1b[96m',
  // Background colors
  bgRed: '\x1b[41m',
  bgGreen: '\x1b[42m',
  bgYellow: '\x1b[43m',
  bgBlue: '\x1b[44m',
} as const;

/** Jaskier brand colors for terminal output */
export const JASKIER_COLORS = {
  primary: ANSI.brightCyan,
  success: ANSI.brightGreen,
  warning: ANSI.brightYellow,
  error: ANSI.brightRed,
  info: ANSI.brightBlue,
  muted: ANSI.dim,
} as const;

/**
 * Get terminal size using Bun's native API or fallback to process.stdout.
 */
export function getTerminalSize(): TerminalSize {
  // Bun exposes terminal size via process.stdout
  const columns = process.stdout.columns ?? 80;
  const rows = process.stdout.rows ?? 24;
  return { columns, rows };
}

/**
 * Clear the terminal screen and move cursor to top-left.
 */
export function clearScreen(): void {
  process.stdout.write('\x1b[2J\x1b[H');
}

/**
 * Move cursor to a specific position (1-based).
 */
export function moveCursor(row: number, col: number): void {
  process.stdout.write(`\x1b[${row};${col}H`);
}

/**
 * Hide the terminal cursor.
 */
export function hideCursor(): void {
  process.stdout.write('\x1b[?25l');
}

/**
 * Show the terminal cursor.
 */
export function showCursor(): void {
  process.stdout.write('\x1b[?25h');
}

/**
 * Render a styled text string with ANSI codes.
 */
export function styled(text: string, ...styles: string[]): string {
  if (styles.length === 0) return text;
  return `${styles.join('')}${text}${ANSI.reset}`;
}

/**
 * Render a horizontal line across the terminal width.
 */
export function horizontalLine(char = '\u2500', width?: number): string {
  const w = width ?? getTerminalSize().columns;
  return char.repeat(w);
}

/**
 * Render a box around text content.
 */
export function box(content: string, title?: string): string {
  const { columns } = getTerminalSize();
  const maxWidth = Math.min(columns - 4, 80);
  const lines = content.split('\n');
  const contentWidth = Math.min(maxWidth, Math.max(...lines.map((l) => l.length), (title?.length ?? 0) + 4));

  const top = title
    ? `\u250c\u2500 ${title} ${'\u2500'.repeat(Math.max(0, contentWidth - title.length - 3))}\u2510`
    : `\u250c${'\u2500'.repeat(contentWidth + 2)}\u2510`;

  const bottom = `\u2514${'\u2500'.repeat(contentWidth + 2)}\u2518`;

  const body = lines.map((line) => {
    const padded = line.padEnd(contentWidth);
    return `\u2502 ${padded} \u2502`;
  });

  return [top, ...body, bottom].join('\n');
}

/**
 * Render a progress bar.
 */
export function progressBar(current: number, total: number, width = 40, label?: string): string {
  const ratio = Math.min(1, Math.max(0, current / total));
  const filled = Math.round(ratio * width);
  const empty = width - filled;
  const bar = `${'█'.repeat(filled)}${'░'.repeat(empty)}`;
  const percent = `${Math.round(ratio * 100)}%`;
  const prefix = label ? `${label} ` : '';
  return `${prefix}${bar} ${percent}`;
}

/**
 * Render a spinner frame (call in a loop with setInterval).
 * Returns one frame of the spinner animation.
 */
export function spinnerFrame(frameIndex: number): string {
  const frames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
  return frames[frameIndex % frames.length]!;
}

/**
 * Create a simple table from data rows.
 */
export function table(headers: string[], rows: string[][]): string {
  const colWidths = headers.map((h, i) => Math.max(h.length, ...rows.map((r) => (r[i] ?? '').length)));

  const headerLine = headers.map((h, i) => h.padEnd(colWidths[i]!)).join(' | ');
  const separator = colWidths.map((w) => '\u2500'.repeat(w)).join('\u2500+\u2500');
  const dataLines = rows.map((row) => row.map((cell, i) => cell.padEnd(colWidths[i]!)).join(' | '));

  return [headerLine, separator, ...dataLines].join('\n');
}
