/**
 * Locale-aware formatting utilities.
 * Uses navigator.language (or i18next current language) instead of hardcoded 'en-US'.
 *
 * i18next is an optional peer dependency — works without it by falling back to navigator.language.
 */

/** Returns the user's preferred locale (i18next > navigator > fallback) */
export function getLocale(): string {
  // Try i18next if available (optional peer dep)
  try {
    // Dynamic import-like access — avoids hard dependency
    const g = globalThis as unknown as { __jaskier_i18n_instance__?: { language?: string } };
    const i18n = g.__jaskier_i18n_instance__;
    if (typeof i18n?.language === 'string' && i18n.language) {
      return i18n.language;
    }
  } catch {
    // i18next not available — fall through
  }
  return navigator.language || 'en-US';
}

/**
 * Register an i18next instance for locale detection.
 * Call this once during app initialization:
 *   `import i18next from 'i18next'; registerI18nInstance(i18next);`
 */
export function registerI18nInstance(instance: { language?: string }): void {
  (globalThis as unknown as { __jaskier_i18n_instance__?: { language?: string } }).__jaskier_i18n_instance__ = instance;
}

/** Format a date to a locale-aware date+time string */
export function formatDateTime(date: Date | number | string): string {
  const d = date instanceof Date ? date : new Date(date);
  return d.toLocaleString(getLocale());
}

/** Format a date to a locale-aware time-only string */
export function formatTime(date: Date | number | string): string {
  const d = date instanceof Date ? date : new Date(date);
  return d.toLocaleTimeString(getLocale());
}

/** Format a date to a locale-aware date-only string */
export function formatDate(date: Date | number | string): string {
  const d = date instanceof Date ? date : new Date(date);
  return d.toLocaleDateString(getLocale());
}

/** Format a number to a locale-aware string */
export function formatNumber(value: number, options?: Intl.NumberFormatOptions): string {
  return new Intl.NumberFormat(getLocale(), options).format(value);
}
